  ["tips.main.master"] = "Main-Control\n|cffffffffEn este control encontrarás los interruptores automáticos y comandos de reinicio.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para mostrar u ocultar las Opciones|r\n|cff999999(Orden de ejecución: Sistema)|r\n\n|cffff0000Clic derecho para mover MultiBot|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.options"] = "Interruptor de opciones\n|cffffffffAbre el panel de configuración de MultiBot con controles deslizantes para los intervalos de acciones.\n(Estadísticas / Talentos / Invitación / Ordenar) y la limitación del chat (Mensajes por segundo / Ráfaga).\nLa configuración se guarda por personaje.|r\n\n|cffff0000Clic izquierdo para abrir o cerrar el panel de opciones|r\n|cff999999(Orden de ejecución: Interfaz)|r",
  ["tips.main.coords"] = "Reset-Coords\n|cffffffffReinicia las coordenadas de las siguientes funciones:\nMultiBar, Inventario, Libro de hechizos, Itemus, Iconos y Selector de recompensas|r\n\n|cffff0000Clic izquierdo para reiniciar coordenadas|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.masters"] = "GameMaster-Switch\n|cffffffffEste interruptor activa o desactiva el control de GameMaster.\nNecesitas permisos de GameMaster para poder activarlo.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control de GameMaster|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.rtsc"] = "RTSC-Switch\n|cffffffffEste interruptor activa o desactiva el control RTSC.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control RTSC|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.raidus"] = "Raidus-Switch\n|cffffffffEste interruptor abrirá o cerrará el Compositor de Banda.|r\n\n|cffff0000Clic izquierdo para abrir o cerrar el Compositor de Banda|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.creator"] = "Creator-Switch\n|cffffffffEste interruptor activa o desactiva el control de creador.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control de creador|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.disperse"] = "Interruptor Disperse\n|cffffffffEste interruptor muestra u oculta el control Disperse.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control Disperse|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.loot"] = "Interruptor de reglas de botín\n|cffffffffEste interruptor muestra u oculta el control de reglas de botín.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control de reglas de botín|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.beast"] = "Beastmaster-Switch\n|cffffffffEste interruptor activa o desactiva el control de domador de bestias.\nEl control Beastmaster es parte del Mod-NPC-Beastmaster de AzerothCore.\nEste módulo permite que cualquier personaje tenga una mascota como los cazadores.\nLos personajes pueden aprender los hechizos necesarios de White Fang.\nWhite Fang debe ser colocado en el mundo por un GameMaster.|r\n\n|cffff0000Clic izquierdo para activar o desactivar el control Beastmaster|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.expand"] = "Expand-Switch\n|cffffffffEste interruptor expandirá o reducirá el control de Stay-Follow.\n|cffff0000Clic izquierdo para expandir o reducir el control Stay-Follow|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.release"] = "Auto-Release\n|cffffffffEsta función detecta la muerte de los bots.\nLos bots muertos son liberados y convocados automáticamente.\nEsto los revivirá en cuestión de segundos.|r\n\n|cffff0000Clic izquierdo para activar o desactivar Auto-Release|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.stats"] = "Auto-Stats\n|cffffffffEsta función visualiza los valores del comando de estadísticas.\nLos valores se actualizan cada 45 segundos.|r\n\n|cffff0000Clic izquierdo para activar o desactivar Auto-Stats|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.reward"] = "Reward-Selector\n|cffffffffEsta función permite seleccionar las recompensas de misiones.\nMi consejo es que elijas la recompensa para tu personaje primero.\nAsí evitarás problemas al usar los botones de inspección.|r\n\nImportante:\nUna vez que tu personaje haya completado la misión, los bots también deben completarla.\nAsí que no canceles el Reward-Selector después de que tu personaje haya obtenido su recompensa.\n\n|cffffffffConfiguración del Mod-Playerbot:\n- (obligatorio) AiPlayerbot.AutoPickReward = no\n- (recomendado) AiPlayerbot.SyncQuestWithPlayer = 1|r\n\n|cffff0000Clic izquierdo para activar o desactivar Reward-Selector|r\n|cff999999(Orden de ejecución: Sistema)|r\n\n|cffff0000Clic derecho para abrir Reward-Selector|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.main.reset"] = "Reset-Bots\n|cffffffffEste botón reinicia la inteligencia artificial de tus bots.|r\n\n|cffff0000Clic izquierdo para reiniciar la IA|r\n|cff999999(Orden de ejecución: Objetivo, Banda, Grupo)|r",
  ["tips.main.action"] = "Reset-Action\n|cffffffffEste botón reinicia la acción actual de tus bots.|r\n\n|cffff0000Clic izquierdo para reiniciar la acción|r\n|cff999999(Orden de ejecución: Objetivo, Banda, Grupo)|r",
  ["tips.game.master"] = "GameMaster-Control\n|cffffffffEn este control encontrarás comandos útiles de GameMaster.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para mostrar u ocultar las Opciones|r\n|cff999999(Orden de ejecución: Sistema)|r\n\n|cffff0000Clic derecho para cerrar MultiBot|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.game.necronet"] = "Necro-Network\n|cffffffffEste botón activa o desactiva la Necro-Network.\nSi está activa, verás botones de cementerios en el mapa del mundo.\nCon ellos puedes teletransportarte al cementerio correspondiente.\nNecesitas permisos de GameMaster para usar esta función.|r\n\n|cffff0000Clic izquierdo para activar o desactivar la Necro-Network|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.game.portal"] = "Memory-Portal\n|cffffffffEn este recuadro encontrarás las gemas de memoria.\nÚsalas para guardar tu ubicación actual.\nPuedes teletransportarte a esas ubicaciones usando las gemas de memoria.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para mostrar u ocultar las gemas de alma|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.game.memory"] = "Memory-Gem\n|cffffffffEsta gema de memoria almacena o teletransporta a una ubicación.\nNecesitas permisos de GameMaster para usar esta función.|r\n\n|cffff0000Clic izquierdo para almacenar o teletransportarte|r\n|cff999999(Orden de ejecución: Tú mismo)|r\n\n|cffff0000Clic derecho para olvidar la ubicación|r\n|cff999999(Orden de ejecución: Tú mismo)|r",
  ["tips.game.itemus"] = "Itemus\n|cffffffffEncontrarás todos los objetos en la caja del GameMaster.\nSolo apunta al jugador o bot, haz clic izquierdo en el objeto y tu deseo se cumplirá.\nImportante: no todos los objetos pueden generarse, deberás probar.|r\n\n|cffff0000Clic izquierdo para abrir o cerrar Itemus|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.game.iconos"] = "Iconos\n|cffffffffAquí encontrarás todos los iconos y sus rutas.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para abrir o cerrar Iconos|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.game.summon"] = "Summon\n|cffffffffConvoca al jugador o bot objetivo a tu posición.\nNecesitas permisos de GameMaster para usar este botón.|r\n\n|cffff0000Clic izquierdo para convocar a tu objetivo|r\n|cff999999(Orden de ejecución: Objetivo)|r",
  ["tips.game.appear"] = "Appear\n|cffffffffApareces en la posición del jugador o bot objetivo.\nNecesitas permisos de GameMaster para usar este botón.|r\n\n|cffff0000Clic izquierdo para aparecer junto a tu objetivo|r\n|cff999999(Orden de ejecución: Objetivo)|r",
  ["tips.game.delsvwarning"] = "|cffff4444ADVERTENCIA|r: Estás a punto de borrar TODAS las variables guardadas de MultiBot.\nEsta acción es irreversible.\n\n¿Deseas continuar?",
  ["tips.game.delsv"] = "Eliminar variables guardadas\n|cffffffffEste botón borrará permanentemente todos los datos del archivo de variables guardadas de MultiBot (MultiBot.lua).\nEsta acción no se puede deshacer. ¡Úsalo con precaución!|r\n\n|cffff0000Clic izquierdo para eliminar|r\n|cff999999(Ejecutado a nivel de sistema)|r",
  ["tips.quests.master"] = "Control de Misiones\n|cffffffffEste control muestra la lista actual de misiones.\nHaz clic izquierdo en las páginas para compartir la misión con tus bots.\nHaz clic derecho en las páginas para abandonar tu misión y la de tus bots.\nEl orden de ejecución muestra el receptor de los comandos.|r\n\n|cffff0000Clic izquierdo para mostrar u ocultar las opciones|r\n|cff999999(Orden de ejecución: Sistema)|r\n\n|cffff0000Clic derecho para actualizar las opciones|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.quests.accept"] = "Aceptar misiones\n|cffffffffEste botón ordena a los bots aceptar todas las misiones del PNJ seleccionado.\n\n|cffff0000Clic izquierdo para aceptar todas las misiones|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.quests.main"] = "Abrir el menú de misiones\n|cffffffffEste botón abre el menú de misiones.\n\n|cffff0000Clic izquierdo para abrir|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.quests.talk"] = "Hablar con PNJ\n|cffffffffEste botón ordena a los bots hablar con el PNJ seleccionado para tomar o entregar una misión.\n\n|cffff0000Clic izquierdo para ordenar|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.quests.talkerror"] = "Por favor selecciona un PNJ para hablar.",
  ["tips.quests.questcomperror"] = "Por favor selecciona un bot para consultar sus misiones.",
  ["tips.quests.sendwhisp"] = "Preguntar al bot",
  ["tips.quests.sendpartyraid"] = "Preguntar al grupo o banda.",
  ["tips.quests.completed"] = "Misiones completadas\n|cffffffffEste botón te permite pedir a un bot o a todos los bots la lista de misiones completadas.\n\n|cffff0000Clic izquierdo para abrir el submenú|r\n|cff999999(Orden de ejecución: Banda, Grupo, bot)|r",
  ["tips.quests.incompleted"] = "Misiones incompletas\n|cffffffffEste botón te permite pedir a un bot o a todos los bots la lista de misiones incompletas.\n\n|cffff0000Clic izquierdo para abrir el submenú|r\n|cff999999(Orden de ejecución: Banda, Grupo, bot)|r",
  ["tips.quests.allcompleted"] = "Todas las misiones\n|cffffffffEste botón te permite pedirle a un bot o a todos los bots la lista de todas las misiones.\n\n|cffff0000Clic izquierdo para abrir el submenú|r\n|cff999999(Orden de ejecución: Banda, Grupo, bot)|r",
  ["tips.quests.incomplist"] = "Misiones actuales del/de los bot(s)",
