  ["tips.quests.incompheader"] = "** Misiones incompletas **",
  ["tips.quests.drop"] = "Abandonar",
  ["tips.quests.botsword"] = "Bots : ",
  ["tips.quests.gobsmaster"] = "Menú de Objetos del Juego\n|cffffffffEste botón abre el menú para usar objetos del juego.|r\n\n|cffff0000Clic izquierdo para abrir|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.quests.gobenter"] = "Usar objeto del juego\n|cffffffffEste botón abre un cuadro para ingresar el nombre del objeto del juego.\n\n|cffff0000Clic izquierdo para abrir el cuadro|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.quests.gobsearch"] = "Buscar objeto del juego\n|cffffffffEste botón abre una ventana que muestra los objetos del juego que los bots pueden usar.\n\n|cffff0000Clic izquierdo para abrir la ventana|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.quests.goberrorname"] = "Por favor ingresa un nombre de objeto válido.",
  ["tips.quests.gobselectboterror"] = "Por favor selecciona el bot al que enviar el comando.",
  ["tips.quests.gobsnameerror"] = "Por favor ingresa un nombre.",
  ["tips.quests.gobctrlctocopy"] = "CTRL + C para copiar",
  ["tips.quests.gobselectall"] = "Seleccionar todo",
  ["tips.quests.gobsfound"] = "Objetos del juego encontrados",
  ["tips.quests.gobpromptname"] = "Nombre del objeto del juego",
  ["tips.quests.gobnosearchdata"] = "No search data captured.",
  ["tips.group.group"] = "Selector de acciones de grupo\n|cffffffffAbre un submenú con las siguientes acciones de grupo:\nBeber, Liberar, Revivir.|r\n\n|cffff0000Clic izquierdo para expandir.|r",
  ["tips.drink.group"] = "Group-Drink\n|cffffffffCon este botón ordenas al grupo que beba.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para ejecutar beber en grupo|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.release.group"] = "Group-Release\n|cffffffffCon este botón, los bots muertos liberarán sus fantasmas al cementerio más cercano.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para liberar al grupo|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.revive.group"] = "Group-Revive\n|cffffffffCon este botón, los bots fantasmas revivirán en el cementerio más cercano.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para revivir al grupo|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.summon.group"] = "Group-Summon\n|cffffffffCon este botón convocas al grupo a tu posición.\nEl orden de ejecución muestra quién recibirá los comandos.|r\n\n|cffff0000Clic izquierdo para convocar al grupo|r\n|cff999999(Orden de ejecución: Banda, Grupo)|r",
  ["tips.allbots.sellallvendor"] = "Vender todos los objetos grises vendibles (TODOS LOS BOTS)|cffffffff\nTodos tus bots (los que aparecen en el panel de Unidades) venderán todos los objetos\nque puedan venderse de forma segura al vendedor que tienes seleccionado.\nLos objetos protegidos (llaves, Piedra de hogar, etc.) nunca se venden.|r\n\n|cffff0000Afecta a todos los bots listados en el panel de Unidades.|r\n|cff999999(Ejecutado por: cada Bot)|r",
  ["tips.allbots.commandsallbots"] = "Te permite enviar comandos a todos los Bots|cffffffff\nTodos tus bots (los que aparecen en el panel de Unidades) ejecutarán el comando\n\n|cffff0000Afecta a todos los bots listados en el panel de Unidades.|r\n|cff999999(Ejecutado por: cada Bot)|r",
  ["tips.allbots.maintenanceallbots"] = "Mantenimiento (TODOS LOS BOTS)|cffffffff\nTodos tus bots (los que aparecen en el panel de Unidades) ejecutarán el comando 'maintenance'.\nÚsalo cuando quieras que cada bot realice su rutina completa de mantenimiento al mismo tiempo.|r\n\n|cffff0000Afecta a todos los bots listados en el panel de Unidades.|r\n|cff999999(Ejecutado por: cada Bot)|r",
  ["tips.inventory.sell"] = "Vender Objetos|cffffffff\nActiva el modo de venta del inventario.\nDebes seleccionar un comerciante.\nPor razones de seguridad, tu Bot no venderá:\n- cada objeto con 'Llave' en su nombre\n- la Piedra de Hogar|r\n\n|cffff0000Clic izquierdo para vender un objeto|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.sellgrey"] = "Vender todo lo gris|cffffffff\nEl Bot vende todos los objetos de calidad mediocre (gris) al comerciante seleccionado.\nAsegúrate de seleccionar un comerciante y que el Bot esté a rango.|r\n\n|cffff0000Solo afecta al Bot cuyo inventario está abierto.|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.sellvendor"] = "Vender todo lo que sea vendible|cffffffff\nEl Bot vende todos los objetos vendibles a este comerciante.\nLos objetos protegidos (Llaves, Piedra de hogar, etc.) nunca serán vendidos.|r\n\n|cffff0000Solo afecta al Bot cuyo inventario está abierto.|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.equip"] = "Equipar Objetos|cffffffff\nActiva el modo de equipamiento del inventario.|r\n\n|cffff0000Clic izquierdo para equipar un objeto|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.use"] = "Usar Objetos|cffffffff\nActiva el modo de uso del inventario.|r\n\n|cffff0000Clic izquierdo para usar un objeto|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.trade"] = "Intercambiar Objetos|cffffffff\nActiva el modo de intercambio del inventario.\nLa ventana de inspección debe cerrarse manualmente.\nNo existe ningún comando LUA para ello.|r\n\n|cffff0000Clic izquierdo para intercambiar un objeto|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.drop"] = "Tirar Objetos|cffffffff\nActiva el modo de descarte del inventario.\nPor razones de seguridad, tu Bot no tirará:\n- cada objeto de calidad Épica o superior\n- cada objeto con 'Llave' en su nombre\n- la Piedra de Hogar|r\n\n|cffff0000Clic izquierdo para tirar un objeto|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.inventory.open"] = "Abrir Objetos|cffffffff\nEste botón abrirá cada bolsa de botín que se encuentre primero en tu inventario.\nEl contenido se colocará automáticamente en el inventario.|r\n\n|cffff0000Clic izquierdo para abrir una bolsa de botín|r\n|cff999999(Orden de ejecución: Bot)|r",
  ["tips.itemus.level.master"] = "Filtro de Nivel|cffffffff\nFiltra los objetos por nivel en rangos de 10.|r\n\n|cffff0000Clic izquierdo para mostrar u ocultar opciones|r\n|cff999999(Orden de ejecución: Sistema)|r",
  ["tips.itemus.level.L10"] = "Nivel 0 a 10|cffffffff\nMuestra los objetos con nivel requerido entre 0 y 10.|r\n\n|cffff0000Clic izquierdo para aplicar el filtro|r\n|cff999999(Orden de ejecución: Sistema)|r",
